Hey,

I think I cracked it, but it's definitely not what I would call "ideal":

```from ldap3 import Server, Connection, NO_ATTRIBUTES, ALL_ATTRIBUTES, MODIFY_REPLACE
from ldap3.operation.search import build_attribute_selection
from ldap3.protocol.controls import build_control

def read_control(oid, attributes, criticality=False, schema=None):
    if not attributes:
        attributes = [NO_ATTRIBUTES]
    elif attributes == ALL_ATTRIBUTES:
        attributes = [ALL_ATTRIBUTES]

    value = build_attribute_selection(attributes, schema)
    return build_control(oid, criticality, value)

def pre_read_control(attributes, criticality=False, schema=None):
    return read_control('1.3.6.1.1.13.1', attributes, criticality, schema)

def post_read_control(attributes, criticality=False, schema=None):
    return read_control('1.3.6.1.1.13.2', attributes, criticality, schema)

server = Server('localhost')
conn = Connection(server, 'cn=admin,dc=glpgs,dc=io', 'ChangeTh1sC4t', auto_bind=True)

conn.modify('cn=uidnext,dc=glpgs,dc=io',
            {'uidNumber' : [(MODIFY_REPLACE, [10002])]},
            controls=[pre_read_control(["uidNumber"], True)])

print(conn.result)
```

