If you want to do the calculations *only* when the value changes instead of in every save, you can do something like this:

```python
@staff_member_required
def config_view(request):
    if not request.user.is_superuser:
        raise Http404

    if request.method == 'POST':
        form = LMSConfigForm(data=request.POST)

        if form.is_valid():
            active_semester_id = form.cleaned_data['lms_active_semester']

            if config.lms_active_semester != active_semester_id:
                Semester.objects.set_active(active_semester_id)

            form.save()
            messages.success(request, "Settings saved")
            return redirect(request.get_full_path())  # Always redirect somewhere after a valid post
    else:
        form = LMSConfigForm()

    return render(request, 'configuration.html', {'form': form, })
```

